var TaskPlanner = class {
	createPlan(goal) {
		return {
			id: Date.now().toString(),
			goal,
			tasks: [{
				id: "task-1",
				description: `Analyze goal: ${goal}`,
				status: "PENDING"
			}],
			status: "PLANNING"
		};
	}
	updateTaskStatus(plan, taskId, status, result) {
		const updatedTasks = plan.tasks.map((t) => t.id === taskId ? {
			...t,
			status,
			result
		} : t);
		const allCompleted = updatedTasks.every((t) => t.status === "COMPLETED");
		const anyFailed = updatedTasks.some((t) => t.status === "FAILED");
		return {
			...plan,
			tasks: updatedTasks,
			status: anyFailed ? "FAILED" : allCompleted ? "COMPLETED" : plan.status
		};
	}
};
