var ModelRouter = class {
	providers = {};
	constructor() {
		this.providers["openai"] = new OpenAIProvider();
		this.providers["custom"] = new OpenAIProvider();
	}
	async chat(messages, config, providerType = "openai") {
		console.log(`[ModelRouter] Routing to ${providerType} with model: ${config.modelName}`);
		const provider = this.providers[providerType.toLowerCase()];
		if (!provider) throw new Error(`Unsupported provider: ${providerType}`);
		return provider.chat(messages, config);
	}
};
var DecisionEngine = class {
	promptManager;
	router;
	constructor() {
		this.promptManager = new PromptManager();
		this.router = new ModelRouter();
	}
	async suggestAction(reasoningContext, context, config, customPrompt = "", provider = "openai") {
		const messages = this.promptManager.buildPrompt(customPrompt, {
			...context,
			reasoningGoal: reasoningContext
		});
		return (await this.router.chat(messages, config, provider)).content;
	}
};
